def verify_remediation(
    source_id: str,
    collection,
    issue_type: str,  # "completeness" | "freshness" | "duplicates"
) -> dict:
    """
    Re-run the quality check that triggered the issue and return pass/fail.
    """
    results = collection.get(where={"source_id": source_id}, include=["metadatas"])

    if issue_type == "completeness":
        required = ["source_id", "classification", "acl", "ingest_timestamp", "content_hash"]
        complete = sum(
            1 for meta in results["metadatas"]
            if all(meta.get(f) for f in required)
        )
        total = len(results["metadatas"])
        rate = complete / total * 100 if total else 0
        return {"passed": rate >= 98.0, "completeness_rate": round(rate, 2)}

    if issue_type == "freshness":
        from datetime import datetime, timezone
        policy = get_freshness_policy(source_id)
        if not policy or not results["metadatas"]:
            return {"passed": False, "reason": "no policy or no chunks"}
        ts = max(m.get("ingest_timestamp", "") for m in results["metadatas"])
        if not ts:
            return {"passed": False, "reason": "no ingest_timestamp"}
        age = datetime.now(timezone.utc) - datetime.fromisoformat(
            ts.rstrip("Z")).replace(tzinfo=timezone.utc)
        return {"passed": age <= policy, "age_days": age.days, "policy_days": policy.days}

    return {"passed": False, "reason": f"unknown issue_type: {issue_type}"}

def close_remediation(issue_id: str, verification: dict, fixed_by: str,
                       log: str = "logs/governance_exceptions.jsonl"):
    import json
    from datetime import datetime, timezone
    from pathlib import Path
    lines = Path(log).read_text().splitlines()
    updated = []
    for line in lines:
        record = json.loads(line)
        if record.get("exception_id") == issue_id:
            record["status"] = "resolved" if verification["passed"] else "verification_failed"
            record["resolved_at"] = datetime.now(timezone.utc).isoformat()
            record["resolved_by"] = fixed_by
            record["verification"] = verification
        updated.append(json.dumps(record))
    Path(log).write_text("\n".join(updated) + "\n")
